#include "SYsULexer.h"
#include <fstream>
#include <iostream>
#include <unordered_map>
#include <regex>
#include <vector>
#include <string>

// Mapping from ANTLR token type to clang token name
std::unordered_map<std::string, std::string> tokenTypeMapping = {
  { "Void", "void" },
  { "Int", "int" },
  { "Return", "return" },
  { "If", "if" },
  { "Else", "else" },
  { "While", "while" },
  { "Break", "break" },
  { "Continue", "continue" },
  { "Identifier", "identifier" },
  { "LeftParen", "l_paren" },
  { "RightParen", "r_paren" },
  { "RightBrace", "r_brace" },
  { "LeftBrace", "l_brace" },
  { "LeftBracket", "l_square" },
  { "RightBracket", "r_square" },
  { "Constant", "numeric_constant" },
  { "Semi", "semi" },
  { "EOF", "eof" },
  { "Equal", "equal" },
  { "EqualEqual", "equalequal" },
  { "NotEqual", "exclaim_equal" },
  { "Less", "less" },
  { "Greater", "greater" },
  { "LessEqual", "lessequal" },
  { "GreaterEqual", "greaterequal" },
  { "Plus", "plus" },
  { "Minus", "minus" },
  { "Star", "star" },
  { "Slash", "slash" },
  { "Percent", "percent" },
  { "Exclaim", "exclaim" },
  { "AmpAmp", "ampamp" },
  { "PipePipe", "pipepipe" },
  { "Amp", "amp" },
  { "Pipe", "pipe" },
  { "Comma", "comma" },
};

// Line info for each preprocessed line
struct LineInfo {
  std::string filename;
  int line;
};

int main(int argc, char* argv[]) {
  if (argc != 3) {
    std::cout << "Usage: " << argv[0] << " <input> <output>\n";
    return -1;
  }

  std::ifstream inFile(argv[1]);
  if (!inFile) {
    std::cout << "Error: unable to open input file: " << argv[1] << '\n';
    return -2;
  }

  std::ofstream outFile(argv[2]);
  if (!outFile) {
    std::cout << "Error: unable to open output file: " << argv[2] << '\n';
    return -3;
  }

  // Read raw content
  std::string rawContent((std::istreambuf_iterator<char>(inFile)),
                          std::istreambuf_iterator<char>());
  inFile.close();

  // Parse line directives to build line mapping
  // lineMap[i] = {filename, line} for preprocessed line i+1
  std::vector<LineInfo> lineMap;
  std::string currentFile;
  int currentLine = 1;

  size_t pos = 0;
  while (pos < rawContent.length()) {
    // Find end of current line
    size_t lineEnd = rawContent.find('\n', pos);
    if (lineEnd == std::string::npos) {
      lineEnd = rawContent.length();
    }
    std::string line = rawContent.substr(pos, lineEnd - pos);
    // Remove trailing \r
    if (!line.empty() && line.back() == '\r') {
      line.pop_back();
    }

    // Check if this is a line directive
    std::regex re(R"xx(^\s*#\s*(\d+)\s+"([^"]*)".*)xx", std::regex::ECMAScript);
    std::smatch match;
    if (std::regex_match(line, match, re)) {
      currentLine = std::stoi(match[1].str());
      currentFile = match[2].str();
    }

    lineMap.push_back({currentFile, currentLine});
    currentLine++;
    pos = lineEnd + 1;
  }

  // Now tokenize
  inFile.open(argv[1]);
  antlr4::ANTLRInputStream input(inFile);
  SYsULexer lexer(&input);
  antlr4::CommonTokenStream tokens(&lexer);
  tokens.fill();
  inFile.close();

  auto& vocabulary = lexer.getVocabulary();
  auto allTokens = tokens.getTokens();

  // Track which tokens are on which preprocessed lines
  // For each line, track if we've seen a non-whitespace token
  std::vector<bool> lineHasToken(lineMap.size(), false);

  for (size_t i = 0; i < allTokens.size(); i++) {
    auto* token = allTokens[i];
    int tokenLine = token->getLine();
    int tokenCol = token->getCharPositionInLine() + 1;
    std::string tokenText = token->getText();

    // Skip EOF token for line tracking
    if (tokenText == "<EOF>") {
      continue;
    }

    // Mark this line as having a token
    if (tokenLine > 0 && tokenLine <= (int)lineMap.size()) {
      lineHasToken[tokenLine - 1] = true;
    }
  }

  // Process each token
  for (size_t i = 0; i < allTokens.size(); i++) {
    auto* token = allTokens[i];
    int tokenLine = token->getLine();
    int tokenCol = token->getCharPositionInLine() + 1;
    std::string tokenText = token->getText();

    auto tokenTypeName = std::string(vocabulary.getSymbolicName(token->getType()));
    if (tokenTypeName.empty()) {
      tokenTypeName = "<UNKNOWN>";
    }

    if (tokenTypeMapping.find(tokenTypeName) != tokenTypeMapping.end()) {
      tokenTypeName = tokenTypeMapping[tokenTypeName];
    }

    // Get location info
    std::string filename;
    int line = tokenLine;
    int col = tokenCol;

    if (tokenLine > 0 && tokenLine <= (int)lineMap.size()) {
      filename = lineMap[tokenLine - 1].filename;
      line = lineMap[tokenLine - 1].line;
    }

    // Determine StartOfLine and LeadingSpace
    bool startOfLine = false;
    bool leadingSpace = false;

    if (tokenText != "<EOF>") {
      // Check if this token is at the start of its line
      // We need to look at the raw text before this token on the same line
      if (tokenLine > 0 && tokenLine <= (int)lineMap.size()) {
        // Find the start of this line in raw content
        int lineStart = 0;
        for (int j = 0; j < tokenLine - 1; j++) {
          size_t nl = rawContent.find('\n', lineStart);
          if (nl != std::string::npos) {
            lineStart = nl + 1;
          }
        }

        // Check if there's any non-whitespace character before this token on the same line
        bool hasNonWhitespaceBefore = false;
        for (int j = lineStart; j < lineStart + tokenCol - 1; j++) {
          if (j < (int)rawContent.length() && rawContent[j] != ' ' && rawContent[j] != '\t' && rawContent[j] != '\r') {
            hasNonWhitespaceBefore = true;
            break;
          }
        }

        startOfLine = !hasNonWhitespaceBefore;

        // Check for leading space
        if (tokenCol > 1) {
          int prevPos = lineStart + tokenCol - 2;
          if (prevPos >= 0 && prevPos < (int)rawContent.length()) {
            char prevChar = rawContent[prevPos];
            leadingSpace = (prevChar == ' ' || prevChar == '\t');
          }
        }
      }
    }

    // Build location string
    std::string locInfo = " Loc=<" + filename + ":" + std::to_string(line) + ":" + std::to_string(col) + ">";

    // Output token
    if (tokenText == "<EOF>") {
      outFile << tokenTypeName << " ''";
      // EOF location: last line + 1, last col + 1
      if (allTokens.size() > 1) {
        auto* lastToken = allTokens[allTokens.size() - 2];
        int lastLine = lastToken->getLine();
        int lastCol = lastToken->getCharPositionInLine() + 1 + lastToken->getText().length();
        std::string lastFilename;
        int lastSourceLine = lastLine;
        if (lastLine > 0 && lastLine <= (int)lineMap.size()) {
          lastFilename = lineMap[lastLine - 1].filename;
          lastSourceLine = lineMap[lastLine - 1].line;
        }
        // EOF is at the next position after the last token
        locInfo = " Loc=<" + lastFilename + ":" + std::to_string(lastSourceLine) + ":" + std::to_string(lastCol) + ">";
      }
    } else {
      outFile << tokenTypeName << " '" << tokenText << "'";
    }

    if (startOfLine) {
      outFile << "\t [StartOfLine]";
    }
    if (leadingSpace) {
      outFile << " [LeadingSpace]";
    }
    outFile << locInfo << std::endl;
  }

  return 0;
}

